describe("conditional options", () => {
  it("requires a dependency by object key and reports its CLI flag", () => {
    const parser = object({
      verbose: flag("--verbose"),
      output: requiredWhen("verbose", "--output", string()),
    });
    const result = parseSync(parser, []);
    assert.ok(!result.success);
    if (!result.success) assertErrorIncludes(result.error, "requires option --verbose");
  });

  it("resolves a dependency by CLI flag through withDefault", () => {
    const parser = object({
      mode: withDefault(option("--mode", string()), "off"),
      output: requiredWhen({ option: "--mode", value: "on" }, "--output", string()),
    });
    const result = parseSync(parser, ["--mode", "on"]);
    assert.ok(!result.success);
    if (!result.success) {
      assertErrorIncludes(result.error, "requires option --mode");
      assertErrorIncludes(result.error, "on");
    }
  });

  it("supports compound conditions and empty condition arrays", () => {
    const parser = object({
      first: flag("--first"),
      second: flag("--second"),
      any: requiredWhen({ anyOf: [] }, "--any"),
      all: conditionalOption({ allOf: [] }, "--all"),
      output: requiredWhen({ allOf: ["first", "second"] }, "--output"),
    });
    const result = parseSync(parser, ["--first", "--second"]);
    assert.ok(!result.success);
    if (!result.success) assertErrorIncludes(result.error, "requires option");
  });

  it("hides an unsatisfied optional dependency without rejecting it", () => {
    const parser = object({
      enabled: flag("--enabled"),
      output: optionalWhen("enabled", "--output", string()),
    });
    const suggestions = [...parser.suggest({
      buffer: [],
      state: parser.initialState,
      optionsTerminated: false,
      usage: parser.usage,
    }, "")];
    assert.ok(!suggestions.some((suggestion) => suggestion.text === "--output"));
    const result = parseSync(parser, ["--output", "file"]);
    assert.ok(result.success);
  });
});

